     if (returnTo) safeRemoveItem(RETURN_TO_KEY)
     const destination = returnTo || getLastRoute() || ROUTES.HOME

-    setStatus(t('authCallback.fetchingUserInfo'))
+    // Track whether the component is still mounted and whether the token
